;===============================================================================
;◆イベント◆

; 初期発生イベント
events = [1, 2, 3, 4, 5, 6]

;-------------------------------------------------------------------------------
*event_1
;[exp] true
*event_2
;[exp] true
*event_3
;[exp] true

@delevent
@wait time=500
@eval exp='f.temp = "priest_" + ["red", "purple", "green"].draw()'
@fg c=&'f.temp + "_nude"'
[texton w=1]
[name n=Girl f=&'f.temp + "_03"']「Oh, you guys are...?」[k]
[if exp='game.isFreeMode']
	We told her we were here to help her.[k]
[else]
	[テオ f=05]「We're here to help you. Now, get out of here!」[k]
[endif]
[name n=Girl f=&'f.temp + "_03"']「Thank you!」[k]
[textoff]
@cl
@se f=period
@notice text="<y>One girl rescued!"
@eval exp='f.rescuedSlaves ++'
@changefloor pimg=void

[eventoff]
;-------------------------------------------------------------------------------
*event_4
;[exp] onObjectTrigger

@barrel
@damage v=&'game.curTarget.addParam("life", 200)'
@notice text=&'"<p>" + game.curTarget.displayName + "<w> had HP restored!"'

[eventoff]
;-------------------------------------------------------------------------------
*event_5
;[exp] ! o.人身売買の証拠をつかめ.accepted && ! o.人身売買の証拠をつかめ.completed

[texton w=0]
[name n=Resident]「What are you guys doing here?」[k]
[リーダー f=06]「Ah...!」[k]
It was wrong to go into someone's house without having any business there. We hurriedly turned back.
 [k]
[textoff]
@eval exp='game.moveToFloorVertically(%[map: "下水道・通路", x: 25, y: 14, lift: "down"])'

[eventoff]
